import React, { useEffect, useRef } from 'react';
import { ShieldCheck } from 'lucide-react';
import { ToastProvider, useToast } from './components/Toast';
import { useConversation } from './state/useConversation';
import ConversationMessage from './components/ConversationMessage';
import ChatInput from './components/ChatInput';
import ReviewPanel from './components/ReviewPanel';
import WelcomeState from './components/WelcomeState';
import TypingIndicator from './components/TypingIndicator';
import Sidebar from './components/Sidebar';
import { DecisionType } from './types';
import { postReview, signalsToStrings } from './lib/api';

const DECISION_COPY: Record<DecisionType, string> = {
  approved: 'Approved — output accepted.',
  rejected: 'Rejected — output discarded.',
  challenged: 'Challenge sent back to Claude.',
  rolled_back: 'Changes rolled back.',
};

const Shell: React.FC = () => {
  const {
    conversationId,
    messages,
    isTyping,
    sendPrompt,
    openCheckpoint,
    closeCheckpoint,
    checkpointTarget,
    applyDecision,
    toggleProtected,
    markRolledBack,
    generateChallenge,
    getMessage,
    getPromptFor,
  } = useConversation();

  const toast = useToast();
  const armedRef = useRef(false);
  const [armed, setArmed] = React.useState(false);
  const scrollAnchor = useRef<HTMLDivElement>(null);

  const checkpointActive = !!checkpointTarget || armed;

  // Auto-scroll to bottom when messages change
  useEffect(() => {
    scrollAnchor.current?.scrollIntoView({ behavior: 'smooth', block: 'end' });
  }, [messages.length, isTyping]);

  // If user armed checkpoint, auto-open it on the next assistant reply
  useEffect(() => {
    if (!armedRef.current) return;
    const last = messages[messages.length - 1];
    if (last && last.role === 'assistant') {
      openCheckpoint(last.id);
      armedRef.current = false;
      setArmed(false);
    }
  }, [messages, openCheckpoint]);

  const checkpointOutput = checkpointTarget
    ? getMessage(checkpointTarget.assistantMessageId)
    : undefined;
  const checkpointPrompt = checkpointTarget
    ? getPromptFor(checkpointTarget.assistantMessageId)
    : undefined;

  const handleDecision = async (decision: DecisionType, note?: string) => {
    if (!checkpointTarget || !checkpointOutput || !checkpointPrompt) return;
    const messageId = checkpointTarget.assistantMessageId;

    // Optimistic UI: inline decision badge
    applyDecision(messageId, decision, note);

    // Toast feedback
    const tone = decision === 'rejected' ? 'warn' : decision === 'rolled_back' ? 'info' : 'success';
    toast.show(DECISION_COPY[decision], tone);

    // Close panel
    closeCheckpoint();

    // Persist
    try {
      await postReview({
        message_id: messageId,
        conversation_id: conversationId,
        decision,
        prompt: checkpointPrompt.content,
        output: checkpointOutput.content,
        signals: signalsToStrings(checkpointOutput.signals ?? []),
        note,
      });
    } catch (e) {
      // Non-blocking — UI already updated
      // eslint-disable-next-line no-console
      console.warn('Failed to persist review decision', e);
    }
  };

  const handleRollback = () => {
    if (!checkpointTarget) return;
    const messageId = checkpointTarget.assistantMessageId;
    markRolledBack(messageId);
    // Apply decision (shows toast, inline badge, closes panel, persists)
    handleDecision('rolled_back');
  };

  const handleToggleProtected = (path: string) => {
    if (!checkpointTarget) return;
    toggleProtected(checkpointTarget.assistantMessageId, path);
  };

  const handleGenerateChallenge = () => {
    if (!checkpointTarget) return undefined;
    return generateChallenge(checkpointTarget.assistantMessageId);
  };

  return (
    <div className="h-screen flex bg-app overflow-hidden">
      {/* Claude-style left sidebar */}
      <Sidebar onNewChat={() => window.location.reload()} />

      {/* Main column — conversation + composer */}
      <div className="flex-1 flex flex-col min-w-0 h-screen">
        {/* Top bar */}
        <header
          className="sticky top-0 z-20 bg-app/85 backdrop-blur-sm border-b border-line-light flex-shrink-0"
          data-testid="top-bar"
        >
          <div className="w-full max-w-3xl mx-auto px-4 sm:px-6 h-14 flex items-center justify-between">
            <div className="flex items-center gap-2 md:invisible">
              <span className="w-7 h-7 rounded-lg bg-ink-900 text-white flex items-center justify-center">
                <ShieldCheck className="w-3.5 h-3.5" strokeWidth={1.75} />
              </span>
              <div className="font-serif text-[15px] text-ink-900 leading-none">
                Claude Checkpoint
              </div>
            </div>
            <div
              className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full border text-[11px] font-medium transition-colors duration-300 ${
                checkpointActive
                  ? 'bg-[#F0FDF4] border-[#BBF7D0] text-[#166534]'
                  : 'bg-white border-line text-ink-500'
              }`}
              data-testid="checkpoint-status"
              aria-live="polite"
            >
              <span
                className={`w-1.5 h-1.5 rounded-full ${
                  checkpointActive ? 'bg-[#16A34A]' : 'bg-ink-400'
                }`}
              />
              {checkpointActive ? 'Checkpoint active' : 'Checkpoint inactive'}
            </div>
          </div>
        </header>

        {/* Conversation (scrolls) */}
        <main className="flex-1 overflow-y-auto">
          <div className="w-full max-w-3xl mx-auto px-4 sm:px-6 flex flex-col gap-8 py-2 pb-8">
            {messages.length === 0 && (
              <WelcomeState onSuggestion={(s) => sendPrompt(s)} />
            )}

            {messages.map((m) => (
              <ConversationMessage
                key={m.id}
                message={m}
                onOpenCheckpoint={m.role === 'assistant' ? openCheckpoint : undefined}
              />
            ))}

            {isTyping && (
              <div className="flex flex-col items-start" data-testid="assistant-typing">
                <TypingIndicator />
              </div>
            )}

            <div ref={scrollAnchor} />
          </div>
        </main>

        {/* Composer — pinned to bottom of main column */}
        <ChatInput
          onSend={sendPrompt}
          onActivateCheckpointHint={() => {
            armedRef.current = true;
            setArmed(true);
          }}
          onCancelArmed={() => {
            armedRef.current = false;
            setArmed(false);
          }}
        />
      </div>

      {/* Review panel — overlays from the right; behaviour unchanged */}
      <ReviewPanel
        open={!!checkpointTarget}
        prompt={checkpointPrompt}
        output={checkpointOutput}
        onClose={closeCheckpoint}
        onDecide={handleDecision}
        onRollback={handleRollback}
        onToggleProtected={handleToggleProtected}
        onGenerateChallenge={handleGenerateChallenge}
      />
    </div>
  );
};

const App: React.FC = () => {
  return (
    <ToastProvider>
      <Shell />
    </ToastProvider>
  );
};

export default App;
